import axios from 'axios';

const backendURL = 'http://localhost:3000/api/ai';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get all AI requests
export const getAllAIRequests = async () => {
    try {
        const response = await axios.get(`${backendURL}/requests`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get all AI requests error:', error);
        throw error;
    }
};

// Create a new AI request
export const createAIRequest = async (requestData) => {
    try {
        const response = await axios.post(`${backendURL}/requests`, requestData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Create AI request error:', error);
        throw error;
    }
};

// Get AI requests by user
export const getAIRequestsByUser = async (userId) => {
    try {
        const response = await axios.get(`${backendURL}/requests/user/${userId}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get AI requests by user error:', error);
        throw error;
    }
};
